/*
 Generated from reviewed Xicheng POI production manifest.
 Apply after backend/yudao/sql/mysql/xunjing-seed-xicheng-p0.sql and after the manifest gate outputs PRODUCTION_POI_MANIFEST_READY.
*/

SET NAMES utf8mb4 COLLATE utf8mb4_unicode_ci;
SET FOREIGN_KEY_CHECKS = 0;

SET @tenant_id := 1;
SET @map_package_id := (
  SELECT `id` FROM `xunjing_resource_package`
  WHERE `package_code` = 'XICHENG-MAP-001' AND `tenant_id` = @tenant_id
  LIMIT 1
);
SET @project_id := (
  SELECT `project_id` FROM `xunjing_resource_package`
  WHERE `id` = @map_package_id AND `tenant_id` = @tenant_id
  LIMIT 1
);
SET @school_id := (
  SELECT `school_id` FROM `xunjing_resource_package`
  WHERE `id` = @map_package_id AND `tenant_id` = @tenant_id
  LIMIT 1
);

DROP PROCEDURE IF EXISTS `xunjing_assert_xicheng_production_seed_ready`;
DELIMITER //
CREATE PROCEDURE `xunjing_assert_xicheng_production_seed_ready`()
BEGIN
  IF @map_package_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'XICHENG-MAP-001 resource package is required before production POI seed';
  END IF;
  IF @project_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'XICHENG-MAP-001 project_id is required before production POI seed';
  END IF;
  IF @school_id IS NULL THEN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'XICHENG-MAP-001 school_id is required before production POI seed';
  END IF;
END//
DELIMITER ;
CALL `xunjing_assert_xicheng_production_seed_ready`();
DROP PROCEDURE IF EXISTS `xunjing_assert_xicheng_production_seed_ready`;

DELETE FROM `xunjing_knowledge_document`
WHERE `tenant_id` = @tenant_id
  AND `package_id` = @map_package_id
  AND `title` LIKE '% POI 级生产来源';

DELETE FROM `xunjing_poi`
WHERE `tenant_id` = @tenant_id
  AND `package_id` = @map_package_id;

DELETE FROM `xunjing_media_asset`
WHERE `tenant_id` = @tenant_id
  AND `package_id` = @map_package_id;

DELETE FROM `xunjing_map_point`
WHERE `tenant_id` = @tenant_id
  AND `package_id` = @map_package_id;





SET @sort_order := 0;
SELECT
  @map_package_id,
  `name`,
  `latitude`,
  `longitude`,
  CONCAT('西城 P0 生产点位，POI 编码：', `poi_code`, '。来源、坐标和内容审核均已通过。'),
  (@sort_order := @sort_order + 1),
  'PUBLISHED',
  'admin',
  NOW(),
  'admin',
  NOW(),
  b'0',
  @tenant_id
FROM `xunjing_poi`
WHERE `tenant_id` = @tenant_id
  AND `package_id` = @map_package_id
ORDER BY `poi_code`;

DELETE FROM `xunjing_public_report`
WHERE `tenant_id` = @tenant_id
  AND `project_id` = @project_id
  AND `title` = '西城 P0 后台生产 POI 状态';


SET FOREIGN_KEY_CHECKS = 1;
